 28:       <button class="btn" @click="loadCampaigns">Refresh</button>
 29:       <table class="data-table" v-if="campaigns.length > 0">
 30:         <thead>
 31:           <tr>
 32:             <th>ID</th>
 33:             <th>Name</th>
 34:             <th>Type</th>
 35:             <th>Active Window</th>
 36:             <th>Daily Cap</th>
 37:             <th>Per Member</th>
 38:           </tr>
 39:         </thead>
