 41:           <tr v-for="campaign in campaigns" :key="campaign.id">
 42:             <td>{{ campaign.id }}</td>
 43:             <td>{{ campaign.name }}</td>
 44:             <td>{{ campaign.campaign_type }}</td>
 45:             <td>{{ campaign.effective_start }} to {{ campaign.effective_end }}</td>
 46:             <td>{{ campaign.daily_redemption_cap }}</td>
