 57:         <select v-model="issueMethod">
 58:           <option value="account_assignment">account_assignment</option>
 59:           <option value="printable_qr">printable_qr</option>
 60:         </select>
 61:         <input v-model="issueMemberCode" placeholder="Member code (optional for QR)" />
 62:       </div>
 63:       <button class="btn" @click="onIssueCoupon">Issue</button>
 64:       <p v-if="lastIssue">
