 88: 
 89: <script setup lang="ts">
 90: import { onMounted, ref } from "vue";
 91: 
 92: import {
 93:   createCampaign,
 94:   issueCoupon,
 95:   listCampaigns,
 96:   redeemCoupon,
 97:   type CampaignRecord,
 98:   type CouponIssueResponse,
 99:   type CouponRedeemResponse,
100: } from "@/services/campaigns";
101: import { useUiStore } from "@/stores/ui";
102: import { notifyError } from "@/utils/feedback";
103: 
104: const ui = useUiStore();
105: 
106: const campaigns = ref<CampaignRecord[]>([]);
107: const errorMessage = ref("");
108: 
109: const campaignName = ref("Promo 10% Off");
110: const campaignType = ref<"percent_off" | "fixed_amount" | "full_reduction">("percent_off");
111: const effectiveStart = ref("2026-01-01");
112: const effectiveEnd = ref("2027-12-31");
113: const dailyCap = ref(200);
114: const memberDailyLimit = ref(1);
115: const percentOff = ref("0.10");
116: const fixedAmount = ref("10.00");
117: const thresholdAmount = ref("50.00");
118: 
119: const issueCampaignId = ref(1);
120: const issueMethod = ref<"account_assignment" | "printable_qr">("printable_qr");
121: const issueMemberCode = ref("");
122: const lastIssue = ref<CouponIssueResponse | null>(null);
123: 
124: const redeemCouponCode = ref("");
125: const redeemMemberCode = ref("");
126: const redeemPreTaxAmount = ref("100.00");
127: const redeemOrderReference = ref("ORDER-001");
128: const lastRedemption = ref<CouponRedeemResponse | null>(null);
129: 
130: async function loadCampaigns() {
131:   try {
132:     errorMessage.value = "";
133:     campaigns.value = await listCampaigns();
134:     if (campaigns.value.length > 0) {
135:       issueCampaignId.value = campaigns.value[0].id;
136:     }
137:   } catch (error) {
138:     errorMessage.value = extractError(error);
139:   }
140: }
141: 
142: async function onCreateCampaign() {
143:   try {
144:     errorMessage.value = "";
145:     await createCampaign({
146:       name: campaignName.value,
147:       campaign_type: campaignType.value,
148:       effective_start: effectiveStart.value,
149:       effective_end: effectiveEnd.value,
150:       daily_redemption_cap: Number(dailyCap.value),
151:       per_member_daily_limit: Number(memberDailyLimit.value),
152:       percent_off: campaignType.value === "percent_off" ? percentOff.value : undefined,
153:       fixed_amount_off:
154:         campaignType.value === "fixed_amount" || campaignType.value === "full_reduction"
155:           ? fixedAmount.value
156:           : undefined,
157:       threshold_amount: campaignType.value === "full_reduction" ? thresholdAmount.value : undefined,
158:     });
159:     await loadCampaigns();
160:     ui.success("Created", "Campaign created and campaign list updated.");
161:   } catch (error) {
162:     errorMessage.value = notifyError(error, "Campaign creation failed.");
163:   }
164: }
165: 
166: async function onIssueCoupon() {
167:   try {
168:     errorMessage.value = "";
169:     lastIssue.value = await issueCoupon({
170:       campaign_id: Number(issueCampaignId.value),
171:       issuance_method: issueMethod.value,
172:       member_code: issueMemberCode.value || undefined,
173:     });
174:     redeemCouponCode.value = lastIssue.value.coupon_code;
175:     ui.success("Posted", `Coupon ${lastIssue.value.coupon_code} issued successfully.`);
176:   } catch (error) {
177:     errorMessage.value = notifyError(error, "Coupon issuance failed.");
178:   }
179: }
180: 
181: async function onRedeemCoupon() {
182:   try {
183:     errorMessage.value = "";
184:     lastRedemption.value = await redeemCoupon({
185:       coupon_code: redeemCouponCode.value,
186:       member_code: redeemMemberCode.value || undefined,
187:       pre_tax_amount: redeemPreTaxAmount.value,
188:       order_reference: redeemOrderReference.value,
189:     });
190:     if (lastRedemption.value.success) {
191:       ui.success("Posted", `Redemption successful (${lastRedemption.value.reason_code}).`);
192:     } else {
193:       ui.info("Posted", `${lastRedemption.value.reason_code}: ${lastRedemption.value.message}`);
194:     }
195:   } catch (error) {
196:     errorMessage.value = notifyError(error, "Coupon redemption failed.");
197:   }
198: }
199: 
200: onMounted(async () => {
201:   await loadCampaigns();
202: });
203: </script>

